// reverseInt reverses the digits of an integer n.
func reverseInt(n int64) int64 {
	s := strconv.FormatInt(n, 10)
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	reversedStr := string(runes)

	// Handle potential leading zeros removal implicitly by ParseInt, 
	// though for the constraints (n <= 1000), simple string reversal is fine.
	// Example: 10 -> "01" -> 1
	reversedNum, _ := strconv.ParseInt(reversedStr, 10, 64)
	return reversedNum
}

// isPrime checks if a number is prime.
func isPrime(k int64) bool {
	if k <= 1 {
		return false
	}
	if k <= 3 {
		return true
	}
	if k%2 == 0 || k%3 == 0 {
